const TWO_PI = Math.PI * 2;

const EPSILON = 0.00000001;

export function bool(chance: number = 0.5) {
	if (chance <= EPSILON) {
		return false;
	}

	const lot = Math.random();
	return lot <= chance;
}

export function int(min: number = 0, max: number = Number.MAX_SAFE_INTEGER): number {
	return min + Math.floor(Math.random() * (max - min));
}

export function float(min: number = 0, max: number = Number.MAX_VALUE): number {
	return min + Math.random() * (max - min);
}

export function float01(): number {
	return float(0, 1);
}

export function sign(plusChance: number = 0.5) {
	const plus = bool(plusChance);

	return plus ? 1 : -1;
}

export function twoPI() {
	return Math.random() * TWO_PI;
}

export function pi() {
	return Math.random() * Math.PI;
}
